    // Fragment (type 2)
    if (nodeType == 2) {
        if ([children count] == 1) {
            return buildViewTree(children[0]);
        }
        UIStackView *stack = [[UIStackView alloc] init];
        stack.translatesAutoresizingMaskIntoConstraints = NO;
        stack.axis = UILayoutConstraintAxisVertical;
        stack.spacing = 0;
        for (NSDictionary *child in children) {
            UIView *childView = buildViewTree(child);
            if (childView) {
                [stack addArrangedSubview:childView];
            }
        }
        return stack;
    }

    // Element (type 0)
    NSDictionary *style = props[@"style"];

    // --- Text ---
    if ([tag isEqualToString:@"Text"]) {
        NSMutableString *text = [NSMutableString string];
        for (NSDictionary *child in children) {
            NSNumber *childType = child[@"type"];
            if ([childType intValue] == 1) {
