        field.borderStyle = UITextBorderStyleRoundedRect;

        NSString *placeholder = props[@"placeholder"];
        if (placeholder) {
            field.placeholder = placeholder;
        }

        NSString *value = props[@"value"];
        if (value) {
            field.text = value;
        }

        NSNumber *secure = props[@"secure"];
        if (secure && [secure boolValue]) {
