// --- App lifecycle ---

@interface GoxAppDelegate : UIResponder <UIApplicationDelegate>
@property (nonatomic, strong) UIWindow *window;
@end

@implementation GoxAppDelegate

- (BOOL)application:(UIApplication *)application
    didFinishLaunchingWithOptions:(NSDictionary *)launchOptions {

    self.window = [[UIWindow alloc] initWithFrame:[UIScreen mainScreen].bounds];
    self.window.backgroundColor = [UIColor whiteColor];

    UIViewController *vc = [[UIViewController alloc] init];
    vc.view.backgroundColor = [UIColor whiteColor];
    self.window.rootViewController = vc;
    [self.window makeKeyAndVisible];

    // Get the view tree from Go
    const char *json = GoxGetTree();
    NSLog(@"GOX: Got tree JSON length: %lu", json ? strlen(json) : 0);

    if (json) {
        NSData *data = [NSData dataWithBytes:json length:strlen(json)];
        GoxFreeString(json);

        NSError *error = nil;
        NSDictionary *tree = [NSJSONSerialization JSONObjectWithData:data
                                                            options:0
                                                              error:&error];
        if (tree && !error) {
            UIView *rootView = buildViewTree(tree);
            if (rootView) {
                [vc.view addSubview:rootView];

                [NSLayoutConstraint activateConstraints:@[
                    [rootView.topAnchor constraintEqualToAnchor:vc.view.safeAreaLayoutGuide.topAnchor],
                    [rootView.bottomAnchor constraintEqualToAnchor:vc.view.safeAreaLayoutGuide.bottomAnchor],
                    [rootView.leadingAnchor constraintEqualToAnchor:vc.view.safeAreaLayoutGuide.leadingAnchor],
                    [rootView.trailingAnchor constraintEqualToAnchor:vc.view.safeAreaLayoutGuide.trailingAnchor],
                ]];

                NSLog(@"GOX: Root view added to screen");
            }
        } else {
            NSLog(@"GOX: JSON parse error: %@", error);
        }
    }

    return YES;
}

@end

int main(int argc, char * argv[]) {
    @autoreleasepool {
        return UIApplicationMain(argc, argv, nil, NSStringFromClass([GoxAppDelegate class]));
    }
}
